1	import { useEffect, useRef, useCallback, useState } from "react";
2	import type {
3	  Shape,
4	  ShapeType,
5	  ShapePatch,
6	  Operation,
7	  UndoEntry,
8	  PresenceUser,
9	  ServerMessage,
10	  ClientMessage,
11	} from "../types.ts";
12	import { getStoredToken } from "../authStore.ts";
13	import { getCanvasDetail, ApiError } from "../api.ts";
14	import { renderScene, hitTest, hitTestHandle } from "../canvasRenderer.ts";
15	import type { CursorInfo } from "../canvasRenderer.ts";
16	import { applyOp } from "../operations.ts";
17	import Toolbar from "./Toolbar.tsx";
18	import type { Tool } from "./Toolbar.tsx";
19	import InvitePanel from "./InvitePanel.tsx";
20	
21	interface CanvasPageProps {
22	  canvasId: string;
23	  onBack: () => void;
24	  onLogout: () => void;
25	}
26	
27	// Interaction mode during mouse drag
28	type DragMode =
29	  | { kind: "none" }
30	  | { kind: "draw"; startX: number; startY: number; previewShape: Shape }
31	  | {
32	      kind: "move";
33	      shapeId: string;
34	      startX: number;
35	      startY: number;
36	      origX: number;
37	      origY: number;
38	    }
39	  | {
40	      kind: "resize";
41	      shapeId: string;
42	      corner: string;
43	      startX: number;
44	      startY: number;
45	      origX: number;
46	      origY: number;
47	      origW: number;
48	      origH: number;
49	    };
50	
51	export default function CanvasPage({
52	  canvasId,
53	  onBack,
54	  onLogout,
55	}: CanvasPageProps) {
56	  // --- State stored in refs for high-frequency access ---
57	  const shapesRef = useRef<Shape[]>([]);
58	  const undoStackRef = useRef<UndoEntry[]>([]);
59	  const redoStackRef = useRef<UndoEntry[]>([]);
60	  const pendingOpsRef = useRef<Set<string>>(new Set());
61	  const cursorsRef = useRef<Map<string, CursorInfo>>(new Map());
62	  const onlineUsersRef = useRef<PresenceUser[]>([]);
63	  const selectedIdRef = useRef<string | null>(null);
64	  const dragModeRef = useRef<DragMode>({ kind: "none" });
65	  const wsRef = useRef<WebSocket | null>(null);
66	  const seqRef = useRef<number>(0);
67	  const canvasRef = useRef<HTMLCanvasElement | null>(null);
68	  const containerRef = useRef<HTMLDivElement | null>(null);
69	  const lastCursorSendRef = useRef<number>(0);
70	  const mountedRef = useRef(false);
71	  const wsInitReceivedRef = useRef(false);
72	
73	  // --- React state for UI that needs re-renders ---
74	  const [currentTool, setCurrentTool] = useState<Tool>("select");
75	  const [fillColor, setFillColor] = useState("#3498db");
76	  const [strokeColor, setStrokeColor] = useState("#000000");
77	  const [undoCount, setUndoCount] = useState(0);
78	  const [redoCount, setRedoCount] = useState(0);
79	  const [onlineUsers, setOnlineUsers] = useState<PresenceUser[]>([]);
80	  const [wsConnected, setWsConnected] = useState(false);
81	  const [wsStatus, setWsStatus] = useState<"connected" | "disconnected" | "reconnecting">("disconnected");
82	  const [reconnectFailed, setReconnectFailed] = useState(false);
83	  const [error, setError] = useState("");
84	
85	  // --- Reconnection state (refs to avoid stale closures) ---
86	  const reconnectAttemptRef = useRef(0);
87	  const reconnectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
88	  const shouldReconnectRef = useRef(false);
89	  const connectWsFnRef = useRef<(() => void) | null>(null);
90	
91	  // --- Cursor lerp state ---
92	  const cursorTargetsRef = useRef<Map<string, { x: number; y: number; timestamp: number }>>(new Map());
93	  const lerpAnimFrameRef = useRef<number>(0);
94	
95	  // --- Rendering ---
96	  const scheduleRender = useCallback(() => {
97	    const canvas = canvasRef.current;
98	    if (!canvas) return;
99	    const ctx = canvas.getContext("2d");
100	    if (!ctx) return;

100	    if (!ctx) return;
101	    const dpr = window.devicePixelRatio || 1;
102	    const rect = canvas.getBoundingClientRect();
103	
104	    const selection = selectedIdRef.current
105	      ? {
106	          shapeId: selectedIdRef.current,
107	          handles: [],
108	        }
109	      : null;
110	
111	    const drag = dragModeRef.current;
112	    const preview = drag.kind === "draw" ? drag.previewShape : null;
113	
114	    renderScene(
115	      ctx,
116	      shapesRef.current,
117	      selection,
118	      cursorsRef.current,
119	      preview,
120	      rect.width,
121	      rect.height,
122	      dpr
123	    );
124	  }, []);
125	
126	  const renderRef = useRef(scheduleRender);
127	  renderRef.current = scheduleRender;
128	
129	  const requestRender = useCallback(() => {
130	    requestAnimationFrame(() => renderRef.current());
131	  }, []);
132	
133	  // --- WebSocket Send Helpers ---
134	  const sendWs = useCallback((msg: ClientMessage) => {
135	    const ws = wsRef.current;
136	    if (ws && ws.readyState === WebSocket.OPEN) {
137	      ws.send(JSON.stringify(msg));
138	    }
139	  }, []);
140	
141	  const sendOp = useCallback(
142	    (op: Operation) => {
143	      const ws = wsRef.current;
144	      if (!ws || ws.readyState !== WebSocket.OPEN) return; // drop if not connected
145	      const opId = crypto.randomUUID();
146	      // Apply optimistically
147	      shapesRef.current = applyOp(shapesRef.current, op);
148	      pendingOpsRef.current.add(opId);
149	      ws.send(JSON.stringify({ type: "op", op, opId } satisfies ClientMessage));
150	      requestRender();
151	    },
152	    [requestRender]
153	  );
154	
155	  const doAction = useCallback(
156	    (forward: Operation, reverse: Operation) => {
157	      const ws = wsRef.current;
158	      if (!ws || ws.readyState !== WebSocket.OPEN) return; // don't push undo for unsent ops
159	      undoStackRef.current = [...undoStackRef.current, { forward, reverse }];
160	      redoStackRef.current = [];
161	      setUndoCount(undoStackRef.current.length);
162	      setRedoCount(0);
163	      sendOp(forward);
164	    },
165	    [sendOp]
166	  );
167	
168	  // --- Undo/Redo ---
169	  const undo = useCallback(() => {
170	    const ws = wsRef.current;
171	    if (!ws || ws.readyState !== WebSocket.OPEN) return; // don't burn history while disconnected
172	    const stack = undoStackRef.current;
173	    if (stack.length === 0) return;
174	    const entry = stack[stack.length - 1];
175	    undoStackRef.current = stack.slice(0, -1);
176	    redoStackRef.current = [...redoStackRef.current, entry];
177	    setUndoCount(undoStackRef.current.length);
178	    setRedoCount(redoStackRef.current.length);
179	    sendOp(entry.reverse);
180	  }, [sendOp]);
181	
182	  const redo = useCallback(() => {
183	    const ws = wsRef.current;
184	    if (!ws || ws.readyState !== WebSocket.OPEN) return; // don't burn history while disconnected
185	    const stack = redoStackRef.current;
186	    if (stack.length === 0) return;
187	    const entry = stack[stack.length - 1];
188	    redoStackRef.current = stack.slice(0, -1);
189	    undoStackRef.current = [...undoStackRef.current, entry];
190	    setUndoCount(undoStackRef.current.length);
191	    setRedoCount(redoStackRef.current.length);
192	    sendOp(entry.forward);
193	  }, [sendOp]);
194	
195	  // --- Color change for selected shape ---
196	  // Track the color before the picker opens for a single undo entry
197	  const colorBeforeRef = useRef<{ fill: string; stroke: string }>({ fill: "", stroke: "" });
198	  const colorTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
199

200	  const handleFillChange = useCallback(
201	    (color: string) => {
202	      setFillColor(color);
203	      const selId = selectedIdRef.current;
204	      if (!selId) return;
205	      // Capture original color on first change of a drag
206	      if (!colorBeforeRef.current.fill) {
207	        const shape = shapesRef.current.find((s) => s.id === selId);
208	        if (shape) colorBeforeRef.current.fill = shape.fill;
209	      }
210	      // Apply visually immediately
211	      shapesRef.current = shapesRef.current.map((s) =>
212	        s.id === selId ? { ...s, fill: color } : s
213	      );
214	      requestRender();
215	      // Debounce: send one op after picker settles
216	      if (colorTimerRef.current) clearTimeout(colorTimerRef.current);
217	      colorTimerRef.current = setTimeout(() => {
218	        const origFill = colorBeforeRef.current.fill;
219	        colorBeforeRef.current.fill = "";
220	        if (origFill && origFill !== color) {
221	          // Revert visual, then go through doAction for proper undo entry
222	          shapesRef.current = shapesRef.current.map((s) =>
223	            s.id === selId ? { ...s, fill: origFill } : s
224	          );
225	          doAction(
226	            { kind: "update", shapeId: selId, props: { fill: color } },
227	            { kind: "update", shapeId: selId, props: { fill: origFill } }
228	          );
229	        }
230	      }, 300);
231	    },
232	    [doAction, requestRender]
233	  );
234	
235	  const handleStrokeChange = useCallback(
236	    (color: string) => {
237	      setStrokeColor(color);
238	      const selId = selectedIdRef.current;
239	      if (!selId) return;
240	      if (!colorBeforeRef.current.stroke) {
241	        const shape = shapesRef.current.find((s) => s.id === selId);
242	        if (shape) colorBeforeRef.current.stroke = shape.stroke;
243	      }
244	      shapesRef.current = shapesRef.current.map((s) =>
245	        s.id === selId ? { ...s, stroke: color } : s
246	      );
247	      requestRender();
248	      if (colorTimerRef.current) clearTimeout(colorTimerRef.current);
249	      colorTimerRef.current = setTimeout(() => {
250	        const origStroke = colorBeforeRef.current.stroke;
251	        colorBeforeRef.current.stroke = "";
252	        if (origStroke && origStroke !== color) {
253	          shapesRef.current = shapesRef.current.map((s) =>
254	            s.id === selId ? { ...s, stroke: origStroke } : s
255	          );
256	          doAction(
257	            { kind: "update", shapeId: selId, props: { stroke: color } },
258	            { kind: "update", shapeId: selId, props: { stroke: origStroke } }
259	          );
260	        }
261	      }, 300);
262	    },
263	    [doAction, requestRender]
264	  );
265	
266	  // --- Canvas coordinate helper ---
267	  const getCanvasCoords = useCallback(
268	    (e: MouseEvent): { x: number; y: number } => {
269	      const canvas = canvasRef.current;
270	      if (!canvas) return { x: 0, y: 0 };
271	      const rect = canvas.getBoundingClientRect();
272	      return {
273	        x: e.clientX - rect.left,
274	        y: e.clientY - rect.top,
275	      };
276	    },
277	    []
278	  );
279	
280	  // --- Mouse Handlers ---
281	  const handleMouseDown = useCallback(
282	    (e: MouseEvent) => {
283	      e.preventDefault(); // prevent text selection during drag
284	      const { x, y } = getCanvasCoords(e);
285	
286	      // Text tool: prompt for text and create shape
287	      if (currentTool === "text") {
288	        const text = prompt("Enter text:");
289	        if (!text) return;
290	        const fontSize = 20;
291	        const newShape: Shape = {
292	          id: crypto.randomUUID(),
293	          type: "text",
294	          x,
295	          y,
296	          width: text.length * fontSize * 0.6,
297	          height: fontSize,
298	          fill: fillColor,
299	          stroke: strokeColor,

300	          strokeWidth: 0,
301	          text,
302	          fontSize,
303	        };
304	        const forward: Operation = { kind: "add", shape: newShape };
305	        const reverse: Operation = { kind: "delete", shapeId: newShape.id };
306	        doAction(forward, reverse);
307	        selectedIdRef.current = newShape.id;
308	        requestRender();
309	        return;
310	      }
311	
312	      // Select tool: hit test
313	      if (currentTool === "select") {
314	        // Check if clicking on a resize handle of selected shape
315	        const selId = selectedIdRef.current;
316	        if (selId) {
317	          const selShape = shapesRef.current.find((s) => s.id === selId);
318	          if (selShape) {
319	            const corner = hitTestHandle(selShape, x, y);
320	            if (corner) {
321	              dragModeRef.current = {
322	                kind: "resize",
323	                shapeId: selId,
324	                corner,
325	                startX: x,
326	                startY: y,
327	                origX: selShape.x,
