5	export type ShapeType = "rectangle" | "ellipse" | "line" | "text";
6	
7	/**
8	 * All coordinates are in canvas pixels with a top-left origin.
9	 * Bounding-box model: (x, y) is the top-left corner.
10	 * For lines, (x, y) is the start point and (x + width, y + height) is the end point.
11	 */
12	export interface Shape {
13	  id: string;
14	  type: ShapeType;
15	  x: number;
16	  y: number;
17	  width: number;
18	  height: number;
19	  fill: string;
20	  stroke: string;
21	  strokeWidth: number;
22	  text?: string;
23	  fontSize?: number;
24	}
25	
26	/**
27	 * Mutable shape fields. Shape identity and type are immutable after creation.
28	 */
29	export interface ShapeProps {
30	  x: number;
31	  y: number;
32	  width: number;
33	  height: number;
34	  fill: string;
35	  stroke: string;
36	  strokeWidth: number;
37	  text?: string;
38	  fontSize?: number;
39	}
40	
41	/**
42	 * Partial update payload used by update operations.
43	 */
44	export type ShapePatch = Partial<ShapeProps>;
45	
46	export type Operation =
47	  | { kind: "add"; shape: Shape }
48	  | { kind: "update"; shapeId: string; props: ShapePatch }
49	  | { kind: "delete"; shapeId: string };
50	
51	/**
52	 * Client maintains per-user undo and redo stacks.
53	 * Server does not have a separate undo concept; it only processes normal operations.
54	 */
55	export interface UndoEntry {
56	  forward: Operation;
57	  reverse: Operation;
58	}
59	
60	export type ClientMessage =
61	  | { type: "op"; op: Operation; opId: string }
62	  | { type: "cursor"; x: number; y: number };
63	
64	export type ServerMessage =
65	  | { type: "init"; shapes: Shape[]; users: PresenceUser[]; seq: number }
66	  | { type: "op"; op: Operation; userId: string; seq: number; opId: string }
67	  | { type: "cursor"; userId: string; username: string; x: number; y: number }
68	  | { type: "join"; user: PresenceUser }
69	  | { type: "leave"; userId: string }
70	  | { type: "error"; message: string };
